// Package reloadstatus records the outcome of the most recent configuration
// reload attempt performed in transactional reload mode. The outcome is kept in
// memory for serving over HTTP and persisted to disk so that it survives a
// restart, letting operators diagnose reload failures after the fact.
package reloadstatus

import (
	"encoding/json"
	"os"
	"path/filepath"
	"sync"
)

// ErrorCategory classifies the reason a reload attempt failed. The zero value
// (CategoryNone) means the last attempt succeeded or none has happened yet.
type ErrorCategory string

const (
	// CategoryNone indicates no error: either no reload has been attempted yet
	// or the most recent attempt succeeded.
	CategoryNone ErrorCategory = "none"
	// CategoryLoadError indicates the configuration file could not be loaded or
	// parsed. No component was reconfigured, so no rollback is attempted.
	CategoryLoadError ErrorCategory = "load_error"
	// CategoryApplyError indicates a component failed to apply the new
	// configuration.
	CategoryApplyError ErrorCategory = "apply_error"
	// CategoryRollbackError indicates that, after an apply failure, the rollback
	// to the last known-good configuration itself failed, leaving the runtime in
	// a mixed state.
	CategoryRollbackError ErrorCategory = "rollback_error"
)

// StateFileName is the name of the file, relative to the TSDB storage
// directory, used to persist the most recent reload outcome.
const StateFileName = "reload_status.json"

// Status is the outcome of a single reload attempt. It is the payload served by
// GET /api/v1/status/reload and the shape persisted to disk.
type Status struct {
	// LastReloadID is an RFC3339 timestamp identifying the most recent reload
	// attempt. It is empty before the first attempt.
	LastReloadID string `json:"last_reload_id"`
	// LastReloadSuccessful reports whether the most recent attempt fully
	// succeeded.
	LastReloadSuccessful bool `json:"last_reload_successful"`
	// ErrorCategory classifies the failure; CategoryNone on success.
	ErrorCategory ErrorCategory `json:"error_category"`
	// ErrorMessage is a human-readable description of the failure, empty on
	// success.
	ErrorMessage string `json:"error_message"`
	// AppliedReloaders lists, in order, the reloaders that applied the new
	// configuration during the attempt.
	AppliedReloaders []string `json:"applied_reloaders"`
	// RollbackAttempted reports whether a rollback to the last known-good
	// configuration was attempted.
	RollbackAttempted bool `json:"rollback_attempted"`
	// RollbackSuccessful reports whether the rollback, if attempted, succeeded.
	RollbackSuccessful bool `json:"rollback_successful"`
	// FailedReloader names the reloader that failed to apply, empty on success.
	FailedReloader string `json:"failed_reloader"`
	// ReloaderTimingsMs maps reloader name to the wall-clock time, in
	// milliseconds, it took to run during the attempt.
	ReloaderTimingsMs map[string]float64 `json:"reloader_timings_ms"`
}

// Initial returns the Status reported before any reload has been attempted.
func Initial() Status {
	return Status{
		LastReloadID:         "",
		LastReloadSuccessful: false,
		ErrorCategory:        CategoryNone,
		AppliedReloaders:     []string{},
		ReloaderTimingsMs:    map[string]float64{},
	}
}

// Store holds the most recent reload Status in memory and persists it to disk.
// It is safe for concurrent use.
type Store struct {
	path string

	mtx    sync.RWMutex
	status Status
}

// NewStore returns a Store that persists to StateFileName under dir. If a valid
// state file already exists it is loaded so the most recent outcome survives a
// restart. A missing or corrupted file is ignored: the Store falls back to the
// initial status and never returns an error, so it cannot prevent startup.
func NewStore(dir string) *Store {
	s := &Store{
		path:   filepath.Join(dir, StateFileName),
		status: Initial(),
	}
	s.load()
	return s
}

// load reads a previously persisted status, ignoring any error.
func (s *Store) load() {
	b, err := os.ReadFile(s.path)
	if err != nil {
		return
	}
	var loaded Status
	if err := json.Unmarshal(b, &loaded); err != nil {
		// Corrupted state must not prevent operation; keep the initial status.
		return
	}
	if loaded.AppliedReloaders == nil {
		loaded.AppliedReloaders = []string{}
	}
	if loaded.ReloaderTimingsMs == nil {
		loaded.ReloaderTimingsMs = map[string]float64{}
	}
	if loaded.ErrorCategory == "" {
		loaded.ErrorCategory = CategoryNone
	}
	s.status = loaded
}

// Get returns a copy of the most recent reload status.
func (s *Store) Get() Status {
	s.mtx.RLock()
	defer s.mtx.RUnlock()
	return s.status.clone()
}

