// The outcome of each attempt is recorded as a single Status in the store.
type transactionalReloader struct {
	store *reloadstatus.Store

	// lastGood is the most recently fully-applied configuration, including the
	// one loaded at startup before any reload attempt. It is the target of a
	// rollback. Access is confined to the single reload goroutine, but guarded
	// for safety.
	mtx      sync.Mutex
	lastGood *config.Config
