func (t *transactionalReloader) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
	start := time.Now()
	logger.Info("Loading configuration file", "filename", filename)

	status := reloadstatus.Status{
		LastReloadID:      start.Format(time.RFC3339),
		ErrorCategory:     reloadstatus.CategoryNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMs: map[string]float64{},
	}

	defer func() {
		if err == nil {
			status.LastReloadSuccessful = true
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			status.LastReloadSuccessful = false
			configSuccess.Set(0)
			callback(false)
		}
		if perr := t.store.Set(status); perr != nil {
			logger.Error("Failed to persist reload status", "err", perr)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		status.ErrorCategory = reloadstatus.CategoryLoadError
		status.ErrorMessage = err.Error()
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	t.mtx.Lock()
	lastGood := t.lastGood
	t.mtx.Unlock()

	for _, rl := range rls {
		rstart := time.Now()
		rerr := rl.reloader(conf)
		status.ReloaderTimingsMs[rl.name] = durationMs(time.Since(rstart))
		if rerr != nil {
			logger.Error("Failed to apply configuration", "reloader", rl.name, "err", rerr)
			status.FailedReloader = rl.name
			status.ErrorCategory = reloadstatus.CategoryApplyError
			status.ErrorMessage = rerr.Error()

			// Roll back only if a component already applied the new config and
			// there is a known-good configuration to restore.
			if len(status.AppliedReloaders) > 0 && lastGood != nil {
				status.RollbackAttempted = true
				if rbErr := rollback(lastGood, status.AppliedReloaders, rls, logger); rbErr != nil {
					status.RollbackSuccessful = false
					status.ErrorCategory = reloadstatus.CategoryRollbackError
					status.ErrorMessage = fmt.Sprintf("failed to apply %q: %v; rollback failed: %v", rl.name, rerr, rbErr)
				} else {
					status.RollbackSuccessful = true
					logger.Info("Rolled back to the last known-good configuration", "reloaders", strings.Join(status.AppliedReloaders, ","))
				}
			}
			return fmt.Errorf("failed to apply configuration for reloader %q (--config.file=%q): %w", rl.name, filename, rerr)
		}
		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
	}

	t.mtx.Lock()
	t.lastGood = conf
	t.mtx.Unlock()

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

// rollback restores the given configuration on the components that already
// applied a new configuration, in the order they were applied. It aggregates
// any per-component rollback errors.
func rollback(lastGood *config.Config, applied []string, rls []reloader, logger *slog.Logger) error {
	byName := make(map[string]reloader, len(rls))
	for _, rl := range rls {
		byName[rl.name] = rl
	}
	var errs []error
	for _, name := range applied {
		rl, ok := byName[name]
		if !ok {
			continue
		}
		if err := rl.reloader(lastGood); err != nil {
			logger.Error("Failed to roll back configuration", "reloader", name, "err", err)
			errs = append(errs, fmt.Errorf("%s: %w", name, err))
		}
	}
	return errors.Join(errs...)
}

func durationMs(d time.Duration) float64 {
	return float64(d) / float64(time.Millisecond)
}

