func TestGetReturnsCopy(t *testing.T) {
	s := NewStore(t.TempDir())
	require.NoError(t, s.Set(Status{
		AppliedReloaders:  []string{"a"},
		ReloaderTimingsMs: map[string]float64{"a": 1},
	}))

	got := s.Get()
	got.AppliedReloaders[0] = "mutated"
	got.ReloaderTimingsMs["a"] = 999

	fresh := s.Get()
	require.Equal(t, "a", fresh.AppliedReloaders[0])
	require.Equal(t, float64(1), fresh.ReloaderTimingsMs["a"])
}

