func TestTransactionalReload_Success(t *testing.T) {
	tr := newTransactionalReloader(t)
	cfgFile := writeConfigFile(t, minimalConfig)

	var order []string
	reloaders := []reloader{
		{name: "a", reloader: func(*config.Config) error { order = append(order, "a"); return nil }},
		{name: "b", reloader: func(*config.Config) error { order = append(order, "b"); return nil }},
	}

	err := tr.reload(cfgFile, false, promslog.NewNopLogger(), noStep(), func(bool) {}, reloaders...)
	require.NoError(t, err)
	require.Equal(t, []string{"a", "b"}, order)

	st := tr.store.Get()
	require.True(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryNone, st.ErrorCategory)
	require.Equal(t, []string{"a", "b"}, st.AppliedReloaders)
	require.False(t, st.RollbackAttempted)
	require.NotEmpty(t, st.LastReloadID)
	require.Contains(t, st.ReloaderTimingsMs, "a")
	require.Contains(t, st.ReloaderTimingsMs, "b")
	require.NotNil(t, tr.lastGood)
}

func TestTransactionalReload_LoadErrorNoRollback(t *testing.T) {
	tr := newTransactionalReloader(t)
	// Seed a known-good config to be sure rollback is NOT invoked on a load error.
	tr.lastGood = &config.Config{}

	var applied int
	reloaders := []reloader{
		{name: "a", reloader: func(*config.Config) error { applied++; return nil }},
	}

	err := tr.reload(writeConfigFile(t, "global: {: bad"), false, promslog.NewNopLogger(), noStep(), func(bool) {}, reloaders...)
	require.Error(t, err)
	require.Zero(t, applied, "no reloader should run when config fails to load")

	st := tr.store.Get()
	require.False(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryLoadError, st.ErrorCategory)
	require.False(t, st.RollbackAttempted)
	require.Empty(t, st.AppliedReloaders)
	require.NotEmpty(t, st.ErrorMessage)
}

func TestTransactionalReload_ApplyFailureRollsBack(t *testing.T) {
	tr := newTransactionalReloader(t)
	cfgFile := writeConfigFile(t, minimalConfig)

	// A successful reload first establishes the last known-good config.
	good := []reloader{
		{name: "a", reloader: func(*config.Config) error { return nil }},
		{name: "b", reloader: func(*config.Config) error { return nil }},
	}
	require.NoError(t, tr.reload(cfgFile, false, promslog.NewNopLogger(), noStep(), func(bool) {}, good...))
	knownGood := tr.lastGood

	// Now "b" fails. "a" already applied, so it must be rolled back to the last
	// known-good config, and "b" must not be recorded as applied.
	var rolledBack []*config.Config
	failing := []reloader{
		{name: "a", reloader: func(c *config.Config) error {
			rolledBack = append(rolledBack, c)
			return nil
		}},
		{name: "b", reloader: func(*config.Config) error { return errors.New("apply boom") }},
	}

	err := tr.reload(cfgFile, false, promslog.NewNopLogger(), noStep(), func(bool) {}, failing...)
	require.Error(t, err)

	st := tr.store.Get()
	require.False(t, st.LastReloadSuccessful)
	require.Equal(t, reloadstatus.CategoryApplyError, st.ErrorCategory)
	require.Equal(t, "b", st.FailedReloader)
	require.Equal(t, []string{"a"}, st.AppliedReloaders)
	require.True(t, st.RollbackAttempted)
	require.True(t, st.RollbackSuccessful)

	// "a" was invoked twice: once during apply, once during rollback with the
	// known-good config.
	require.Len(t, rolledBack, 2)
	require.Same(t, knownGood, rolledBack[1])

	// lastGood is unchanged after a failed reload.
	require.Same(t, knownGood, tr.lastGood)
}

